{
  "title": "人工智能发展简史",
  "chapters": [
    {
      "title": "引言：AI的定义与历史脉络",
      "pages": [
        {
          "title": "什么是人工智能？",
          "bullets": [
            "AI是使机器模拟人类感知、学习、推理、决策和行动能力的科学与技术",
            "核心目标：构建能完成通常需人类智能的任务的系统",
            "区别于自动化：强调适应性、泛化性与自主性"
          ],
          "notes": "开场提问互动：‘你今天用过AI吗？’列举手机语音助手、推荐系统等日常例子；强调AI不是新概念，而是持续演进的技术范式。"
        },
        {
          "title": "历史分期逻辑说明",
          "bullets": [
            "按技术范式、代表性成果、社会影响三维度划分阶段",
            "每阶段呈现‘突破—应用—局限—转折’循环特征",
            "避免线性进步观：强调寒冬与复兴交替的辩证发展"
          ],
          "notes": "用时间轴图示过渡到下一章；提示学生注意‘技术可行性’与‘社会预期’错位常引发寒冬。"
        }
      ]
    },
    {
      "title": "奠基与震荡：1950s–1970s",
      "pages": [
        {
          "title": "萌芽期（1950s–1960s）：从图灵测试到学科诞生",
          "bullets": [
            "1950年图灵提出‘模仿游戏’（图灵测试），奠定智能判定哲学基础",
            "1956年达特茅斯会议正式命名‘Artificial Intelligence’，确立学科身份",
            "早期里程碑：逻辑理论家（首个人工智能程序）、感知机（首个可训练神经网络）"
          ],
          "notes": "强调麦卡锡‘人工智能’一词的原创性；对比当时计算机仅数千字节内存，突显思想超前性。"
        },
        {
          "title": "第一次寒冬（1960s末–1970s初）",
          "bullets": [
            "算力瓶颈：真空管/晶体管计算机无法支撑复杂搜索与学习",
            "理论局限：感知机被证明无法解决异或（XOR）等非线性问题（Minsky & Papert, 1969）",
            "莱特希尔报告（1973）直接导致英美政府撤资，学术信心受挫"
          ],
          "notes": "举例说明‘异或问题’：用简单真值表演示为何单层感知机失效；类比为‘AI青春期的第一次挫折教育’。"
        }
      ]
    },
    {
      "title": "知识驱动时代：1980s–1990s",
      "pages": [
        {
          "title": "专家系统繁荣（1980s）",
          "bullets": [
            "核心思想：将人类专家经验编码为‘if-then’规则库",
            "代表性系统：MYCIN（医疗诊断）、XCON（DEC公司配置系统，年省4000万美元）",
            "日本第五代计算机计划（1982）激发全球AI竞赛，但硬件与软件脱节致失败"
          ],
          "notes": "展示XCON系统截图（简化版流程图）；指出其成功恰暴露弱点：知识获取难、维护成本高、无法自学。"
        },
        {
          "title": "机器学习转向（1990s）",
          "bullets": [
            "符号主义衰落：专家系统难以扩展，催生数据驱动新范式",
            "SVM（1995）与随机森林（1997）成为统计学习标杆",
            "深蓝战胜卡斯帕罗夫（1997）：暴力搜索+领域优化，非通用智能"
          ],
          "notes": "对比深蓝与AlphaGo：前者是‘超级计算器’，后者是‘学习型棋手’；强调1990年代是‘方法论静默革命’。"
        }
      ]
    },
    {
      "title": "深度学习革命：2010s",
      "pages": [
        {
          "title": "算力、数据与算法的三重突破",
          "bullets": [
            "GPU并行计算使神经网络训练提速百倍（AlexNet, 2012）",
            "ImageNet数据集（1400万标注图像）提供规模化训练基础",
            "ReLU激活函数、Dropout正则化等关键技术缓解梯度消失与过拟合"
          ],
          "notes": "播放10秒AlexNet错误率对比动效（15.3% vs 26.2%）；解释‘为什么2012年是分水岭’而非更早。"
        },
        {
          "title": "从视觉到语言：深度模型的疆域拓展",
          "bullets": [
            "Seq2Seq（2014）开启端到端神经机器翻译",
            "Transformer架构（2017）摒弃RNN，实现并行训练与长程依赖建模",
            "BERT（2018）与GPT-1（2018）奠定预训练+微调范式"
          ],
          "notes": "用‘Transformer是AI界的HTTP协议’类比：统一接口，释放生态创新；提醒学生注意‘预训练’本质是压缩互联网知识。"
        }
      ]
    },
    {
      "title": "大模型与生成式AI：2020s至今",
      "pages": [
        {
          "title": "ChatGPT引爆点（2022）",
          "bullets": [
            "基于GPT-3.5微调，融合监督微调（SFT）与基于人类反馈的强化学习（RLHF）",
            "用户增长纪录：5天破百万，2个月破亿——超越Instagram与TikTok初期增速",
            "标志性意义：首次让非技术用户直观感受‘类人对话’能力"
          ],
          "notes": "现场演示ChatGPT输入‘用Python写一个快速排序’并对比传统搜索引擎结果；强调RLHF是‘对齐人类偏好的关键一步’。"
        },
        {
          "title": "全球大模型生态格局",
          "bullets": [
            "美国：OpenAI（GPT系列）、Anthropic（Claude）、Google（Gemini）",
            "中国：文心一言（百度）、通义千问（阿里）、ChatGLM（智谱）、DeepSeek（深度求索）",
            "开源运动加速：Llama系列、Qwen、Phi-3推动技术民主化"
          ],
          "notes": "展示2023–2025主流模型参数量与发布时间热力图；指出‘闭源领先性能，开源驱动创新速度’的双轨趋势。"
        }
      ]
    },
    {
      "title": "挑战与未来：走向可信与具身AI",
      "pages": [
        {
          "title": "当前核心挑战",
          "bullets": [
            "幻觉（Hallucination）：模型自信生成错误事实，检测与缓解仍不成熟",
            "能耗危机：训练GPT-3排放约552吨CO₂，相当于120辆汽车年排放",
            "对齐难题：如何确保AI目标与人类长期福祉一致？"
          ],
          "notes": "举例幻觉：‘爱因斯坦发明了电话’；用‘AI是超级实习生，但没上过伦理课’比喻对齐问题。"
        },
        {
          "title": "前沿探索方向",
          "bullets": [
            "小模型（TinyML）：在手机/传感器端实时运行，降低延迟与隐私风险",
            "AI Agent：具备目标分解、工具调用、反思迭代能力的自主体",
            "具身智能：AI+机器人，在物理世界感知-规划-行动闭环"
          ],
          "notes": "播放Figure 1视频片段（Figure 1机器人开柜取药）；总结：‘从‘会说’到‘会做’，是AGI必经之路’。"
        }
      ]
    },
    {
      "title": "结语：AI史即人类认知进化史",
      "pages": [
        {
          "title": "历史启示与工程思维",
          "bullets": [
            "技术发展非线性：寒冬孕育突破，泡沫催生基建（如GPU、云平台）",
            "跨学科本质：AI进步依赖数学、神经科学、语言学、认知心理学协同",
            "工程师责任：在效率追求之外，必须嵌入鲁棒性、可解释性、公平性设计"
          ],
          "notes": "引用图灵原话收尾：‘我们只能看到很短的未来，但足以看清那里有许多工作要做。’ 鼓励学生以建设者而非旁观者姿态参与AI未来。"
        }
      ]
    }
  ]
}
